{
  "grammar": [
    {
      "pattern": "不要 + food + 辣 / 鹽 / 油",
      "structure": ["不要", "food", "辣/鹽/油"],
      "explanation_en": "Use '不要' (bù yào) before a food item and a seasoning to specify that you do not want that seasoning. This is a polite way to customize your order.",
      "title": "不要 + 辣 / 鹽 / 油",
      "meaning": "I don't want [seasoning] in [food].",
      "when_to_use": ["When ordering food and you want to exclude a specific seasoning like spice, salt, or oil.", "When you have dietary restrictions or preferences."],
      "when_not_to_use": ["When you want to add something (use '加' instead).", "When you want to reduce but not eliminate a seasoning (use '少' instead)."],
      "pragmatic_notes": "In Taiwan, it's common to say '不要辣' for no spice, especially at noodle shops or night markets. Using '不要' is direct but polite in this context.",
      "word_order_notes": "Place '不要' before the food item and the seasoning. For example: '不要辣牛肉麵' (no spicy beef noodles).",
      "english_contrast": "In English, you might say 'no spice' or 'without spice'. In Chinese, the structure is '不要 + food + seasoning'.",
      "korean_contrast": "In Korean, you might say '매운 거 빼 주세요' (please remove the spicy). In Chinese, '不要' is more direct.",
      "negative_examples": [
        {
          "text": "辣不要牛肉麵",
          "error": "Incorrect word order. '不要' must come before the food item."
        }
      ],
      "incorrect_examples": [
        {
          "text": "不要牛肉麵辣",
          "error": "Incorrect word order. The seasoning should come after the food item."
        }
      ],
      "transformation_drills": ["Change '不要辣' to '少辣' (less spicy).", "Change '不要鹽' to '加鹽' (add salt)."],
      "production_drills": ["Order a bowl of beef noodles without spice.", "Order fried rice without salt."],
      "common_error_patterns": ["Placing '不要' after the food item.", "Using '沒有' instead of '不要'."],
      "repair_feedback": {
        "word_order": "Remember: '不要' comes before the food, then the seasoning.",
        "politeness": "Using '不要' is fine, but adding '麻煩' (má fan) makes it more polite.",
        "vocabulary": "Use '辣' for spicy, '鹽' for salt, '油' for oil."
      }
    },
    {
      "pattern": "可以 + verb + 嗎？",
      "structure": ["可以", "verb", "嗎"],
      "explanation_en": "Use '可以...嗎？' to politely ask for permission or make a request. This is a common polite form in Taiwan.",
      "title": "可以...嗎？",
      "meaning": "May I...? / Can I...?",
      "when_to_use": ["When asking for permission to do something, like changing an order.", "When making a polite request to a server or staff."],
      "when_not_to_use": ["When making a direct command (use '請' instead).", "When asking about ability (use '會' instead)."],
      "pragmatic_notes": "In Taiwan, '可以...嗎？' is very polite and commonly used in restaurants. It softens the request and shows respect.",
      "word_order_notes": "Place '可以' at the beginning of the sentence, followed by the verb, and end with '嗎'.",
      "english_contrast": "In English, you might say 'Can I...?' or 'May I...?'. In Chinese, '可以...嗎？' is the equivalent.",
      "korean_contrast": "In Korean, you might say '~해도 될까요?' (may I do...?). In Chinese, '可以...嗎？' is similar.",
      "negative_examples": [
        {
          "text": "可以嗎換一份？",
          "error": "Incorrect word order. The verb should come after '可以' and before '嗎'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "可以換一份？",
          "error": "Missing '嗎' at the end. Without '嗎', it sounds like a statement, not a question."
        }
      ],
      "transformation_drills": ["Change '可以換一份嗎？' to '可以退掉嗎？' (can I cancel it?).", "Change '可以加飯嗎？' to '可以加蛋嗎？' (can I add an egg?)."],
      "production_drills": ["Ask if you can change your order.", "Ask if you can get a box for leftovers."],
      "common_error_patterns": ["Omitting '嗎' at the end.", "Using '可以' after the verb."],
      "repair_feedback": {
        "word_order": "Remember: '可以' + verb + '嗎'.",
        "politeness": "This structure is already polite. Adding '不好意思' before it makes it even more polite.",
        "vocabulary": "Use verbs like '換' (change), '退' (cancel), '加' (add)."
      }
    },
    {
      "pattern": "Subject + 點錯 / 送錯 / 拿錯 + object + 了",
      "structure": ["Subject", "點錯/送錯/拿錯", "object", "了"],
      "explanation_en": "Use '錯' (cuò) after a verb to indicate that the action was done incorrectly. '了' (le) marks the completion or change of state.",
      "title": "Verb + 錯 + 了",
      "meaning": "Made a mistake in [verb]ing [object].",
      "when_to_use": ["When you ordered the wrong item.", "When the server brought the wrong dish.", "When you picked up the wrong item."],
      "when_not_to_use": ["When you want to say something is bad quality (use '不好吃' instead).", "When you want to say something is missing (use '少了' instead)."],
      "pragmatic_notes": "In Taiwan, it's common to say '點錯了' (ordered wrong) or '送錯了' (delivered wrong) to politely point out a mistake. Adding '不好意思' softens the complaint.",
      "word_order_notes": "Place '錯' immediately after the verb, then the object, then '了'.",
      "english_contrast": "In English, you might say 'I ordered the wrong thing'. In Chinese, the structure is 'verb + 錯 + object + 了'.",
      "korean_contrast": "In Korean, you might say '잘못 시켰어요' (ordered wrong). In Chinese, '點錯了' is similar.",
      "negative_examples": [
        {
          "text": "我點錯",
          "error": "Missing '了' at the end. '了' is needed to indicate the mistake has occurred."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我錯了點餐",
          "error": "Incorrect word order. '錯' must come after the verb '點'."
        }
      ],
      "transformation_drills": ["Change '我點錯了' to '我拿錯了' (I picked up the wrong one).", "Change '店員送錯了' to '店員做錯了' (the staff made it wrong)."],
      "production_drills": ["Tell the server they brought the wrong dish.", "Tell the cashier you ordered the wrong drink."],
      "common_error_patterns": ["Placing '錯' before the verb.", "Omitting '了' at the end."],
      "repair_feedback": {
        "word_order": "Remember: verb + 錯 + object + 了.",
        "politeness": "Add '不好意思' before the sentence to make it more polite.",
        "vocabulary": "Use '點' for order, '送' for deliver, '拿' for pick up."
      }
    }
  ]
}
